import {
  ChangeDetectionStrategy,
  Component,
  EventEmitter,
  HostListener,
  Input,
  Output,
  computed,
  signal
} from '@angular/core';
import {
  ScheduleAppointmentLab,
  ScheduleAppointmentLabOrder
} from '../../models/schedule.model';

@Component({
  selector: 'app-labs-modal',
  standalone: true,
  templateUrl: './labs-modal.html',
  styleUrl: './labs-modal.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class LabsModalComponent {
  @Input({ required: true }) patientName!: string;
  @Input() labs: ScheduleAppointmentLab[] = [];
  @Input() labOrders: ScheduleAppointmentLabOrder[] = [];
  @Input() lookbackHours: number | null = null;
  @Output() readonly close = new EventEmitter<void>();

  readonly ordersExpanded = signal(true);
  readonly resultsExpanded = signal(true);
  readonly orderSearch = signal('');
  readonly resultSearch = signal('');

  readonly filteredOrders = computed<ScheduleAppointmentLabOrder[]>(() => {
    const q = this.orderSearch().toLowerCase().trim();
    if (!q) return this.labOrders;
    return this.labOrders.filter(o =>
      o.order_mnemonic.toLowerCase().includes(q)
      || o.order_status.toLowerCase().includes(q)
      || o.dept_status.toLowerCase().includes(q)
      || o.order_dt_tm.toLowerCase().includes(q)
      || o.performed_by.toLowerCase().includes(q)
    );
  });

  readonly filteredLabs = computed<ScheduleAppointmentLab[]>(() => {
    const q = this.resultSearch().toLowerCase().trim();
    if (!q) return this.labs;
    return this.labs.filter(l =>
      l.event_name.toLowerCase().includes(q)
      || l.result_value.toLowerCase().includes(q)
      || l.result_units.toLowerCase().includes(q)
      || l.result_status.toLowerCase().includes(q)
      || l.normalcy.toLowerCase().includes(q)
      || l.performed_by.toLowerCase().includes(q)
      || l.event_dt_tm.toLowerCase().includes(q)
    );
  });

  onBackdropClick(): void { this.close.emit(); }

  onDialogClick(event: Event): void { event.stopPropagation(); }

  @HostListener('document:keydown.escape')
  onEscape(): void { this.close.emit(); }

  toggleOrders(): void { this.ordersExpanded.update(v => !v); }

  toggleResults(): void { this.resultsExpanded.update(v => !v); }

  onOrderSearch(event: Event): void {
    this.orderSearch.set((event.target as HTMLInputElement).value);
  }

  onResultSearch(event: Event): void {
    this.resultSearch.set((event.target as HTMLInputElement).value);
  }

  normalcyClass(normalcy: string): string {
    const n = (normalcy ?? '').toLowerCase();
    if (n.includes('critical')) return 'normalcy-critical';
    if (n.includes('abnormal') || n.includes('high') || n.includes('low')) return 'normalcy-abnormal';
    return '';
  }
}
