import { Component, inject, OnInit, OnDestroy, computed, signal, effect, untracked, ChangeDetectionStrategy } from '@angular/core';
import { ScheduleService } from '../../services/schedule.service';
import { ConfigurationService } from '../../services/configuration.service';
import { PreferencesService } from '../../services/preferences.service';
import { AccessControlService } from '../../services/access-control.service';
import {
  ScheduleAppointment,
  COLUMN_DEFINITIONS,
  ColumnDefinition,
  SuperuserGroupOverride,
  SUPERUSER_OVERRIDE_ALL
} from '../../models/schedule.model';
import { openChart, MPageService } from '@clinicaloffice/mpage-developer';
import { LabsModalComponent } from '../labs-modal/labs-modal';

@Component({
  selector: 'app-schedule-list',
  standalone: true,
  imports: [LabsModalComponent],
  templateUrl: './schedule-list.html',
  styleUrl: './schedule-list.scss',
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class ScheduleListComponent implements OnInit, OnDestroy {
  readonly scheduleService = inject(ScheduleService);
  private readonly configService = inject(ConfigurationService);
  readonly preferencesService = inject(PreferencesService);
  readonly accessControlService = inject(AccessControlService);
  private readonly mPage = inject(MPageService);


  readonly dragColumnIndex = signal<number | null>(null);
  readonly dropTargetIndex = signal<number | null>(null);
  readonly labsModalAppt = signal<ScheduleAppointment | null>(null);

  readonly orderedColumns = computed((): ColumnDefinition[] => {
    const order = this.preferencesService.columnOrder();
    return order
      .map(key => COLUMN_DEFINITIONS.find(c => c.key === key))
      .filter((c): c is ColumnDefinition => c !== undefined);
  });

  readonly sortedAppointments = computed((): ScheduleAppointment[] => {
    const appointments = this.scheduleService.filteredAppointments();
    const sortCol = this.preferencesService.sortColumn();
    const sortDir = this.preferencesService.sortDirection();

    if (!sortCol || !sortDir) return appointments;

    return [...appointments].sort((a, b) => {
      const aVal = (a as any)[sortCol] ?? '';
      const bVal = (b as any)[sortCol] ?? '';
      const cmp = String(aVal).localeCompare(String(bVal));
      return sortDir === 'asc' ? cmp : -cmp;
    });
  });

  private initialLoadDone = false;

  private readonly configEffect = effect(() => {
    const loaded = this.configService.isLoaded();
    if (loaded && !this.initialLoadDone) {
      this.initialLoadDone = true;
      untracked(() => {
        if (this.accessControlService.hasScheduleAccess()) {
          this.scheduleService.loadAppointments();
          this.scheduleService.startAutoRefresh();
        }
      });
    }
  });

  ngOnInit(): void {
    // Initial load handled by configEffect when config is ready
  }

  ngOnDestroy(): void {
    this.scheduleService.stopAutoRefresh();
  }

  onStartDateChange(event: Event): void {
    const iso = (event.target as HTMLInputElement).value;
    if (iso) {
      const d = new Date(iso + 'T00:00:00');
      this.scheduleService.setStartDate(this.scheduleService.formatDateForDisplay(d));
    }
  }

  onEndDateChange(event: Event): void {
    const iso = (event.target as HTMLInputElement).value;
    if (iso) {
      const d = new Date(iso + 'T00:00:00');
      this.scheduleService.setEndDate(this.scheduleService.formatDateForDisplay(d));
    }
  }

  toIsoDate(displayDate: string): string {
    const d = this.scheduleService.parseDateFromDisplay(displayDate);
    const yyyy = d.getFullYear();
    const mm = String(d.getMonth() + 1).padStart(2, '0');
    const dd = String(d.getDate()).padStart(2, '0');
    return `${yyyy}-${mm}-${dd}`;
  }

  onPhysicianChange(event: Event): void {
    const value = (event.target as HTMLSelectElement).value;
    this.preferencesService.setPhysicianFilter(value ? Number(value) : null);
  }

  onGroupPickerChange(event: Event): void {
    const value = (event.target as HTMLSelectElement).value;
    const next: SuperuserGroupOverride = value === SUPERUSER_OVERRIDE_ALL ? SUPERUSER_OVERRIDE_ALL : value;
    this.accessControlService.setSelectedGroupId(next);
    this.scheduleService.refresh();
  }

  onSortColumn(columnKey: string): void {
    const def = COLUMN_DEFINITIONS.find(c => c.key === columnKey);
    if (def?.sortable === false) return;

    const currentCol = this.preferencesService.sortColumn();
    const currentDir = this.preferencesService.sortDirection();

    if (currentCol !== columnKey) {
      this.preferencesService.setSortColumn(columnKey, 'asc');
    } else if (currentDir === 'asc') {
      this.preferencesService.setSortColumn(columnKey, 'desc');
    } else {
      this.preferencesService.setSortColumn(null, null);
    }
  }

  isSortable(columnKey: string): boolean {
    return COLUMN_DEFINITIONS.find(c => c.key === columnKey)?.sortable !== false;
  }

  getSortIndicator(columnKey: string): string {
    if (!this.isSortable(columnKey)) return '';
    if (this.preferencesService.sortColumn() !== columnKey) return '';
    return this.preferencesService.sortDirection() === 'asc' ? ' \u25B2' : ' \u25BC';
  }

  getStatusClass(status: string): string {
    const s = status?.toLowerCase() ?? '';
    if (s.includes('confirm')) return 'badge-confirmed';
    if (s.includes('checked') || s.includes('check')) return 'badge-checked-in';
    if (s.includes('pending')) return 'badge-pending';
    if (s.includes('cancel')) return 'badge-cancelled';
    if (s.includes('no show') || s.includes('noshow')) return 'badge-no-show';
    return 'badge-muted';
  }

  getCellValue(appointment: ScheduleAppointment, key: string): string {
    if (key === 'attending_physician') {
      return appointment.attending_physician
        || appointment.ordering_provider
        || appointment.scheduling_resource
        || '\u2014';
    }
    return (appointment as any)[key] ?? '\u2014';
  }

  trackBySchEventId(_index: number, appointment: ScheduleAppointment): number {
    return appointment.sch_event_id;
  }

  onOpenChart(appt: ScheduleAppointment): void {
    if (!appt.person_id) return;
    const encntrId = appt.encntr_id || appt.chart_link_encntr_id || 0;
    if (encntrId) {
      const fallback = !appt.encntr_id && appt.chart_link_encntr_id ? ' (recurring master fallback)' : '';
      this.mPage.putLog('Opening chart for ' + appt.patient_name + fallback);
      openChart(appt.person_id, encntrId);
    } else {
      this.mPage.putLog('Opening chart for ' + appt.patient_name + ' (person only, no encounter)');
      const applink = (window as any).APPLINK;
      if (typeof applink === 'function') {
        applink(0, 'Powerchart.exe', '/PERSONID=' + appt.person_id);
      } else {
        this.mPage.putLog('APPLINK not available (outside Cerner context)');
      }
    }
  }

  async onOpenApptView(appt: ScheduleAppointment): Promise<void> {
    if (!appt.sch_event_id) return;
    this.mPage.putLog('Opening appointment view for sch_event_id: ' + appt.sch_event_id);
    try {
      const schedulingActions = await (window as any).external.DiscernObjectFactory('PEXSCHEDULINGACTIONS');
      schedulingActions.ShowView(appt.sch_event_id, 0);
    } catch (e) {
      this.mPage.putLog('Appointment view not available (outside Cerner context)');
    }
  }

  onOpenLabs(appt: ScheduleAppointment): void {
    this.labsModalAppt.set(appt);
  }

  onCloseLabs(): void {
    this.labsModalAppt.set(null);
  }

  async onOpenOrderInfo(appt: ScheduleAppointment): Promise<void> {
    if (!appt.order_id) return;
    this.mPage.putLog('Opening order info viewer for order_id: ' + appt.order_id);
    try {
      const orderInfoViewer = await (window as any).external.DiscernObjectFactory('PVVIEWERMPAGE');
      await orderInfoViewer.LaunchOrderInfoViewer(appt.order_id, 1);
    } catch (e) {
      this.mPage.putLog('Order info viewer not available (outside Cerner context)');
    }
  }

  onDragStart(event: DragEvent, index: number): void {
    this.dragColumnIndex.set(index);
    if (event.dataTransfer) {
      event.dataTransfer.effectAllowed = 'move';
    }
  }

  onDragOver(event: DragEvent, index: number): void {
    event.preventDefault();
    this.dropTargetIndex.set(index);
  }

  onDragLeave(): void {
    this.dropTargetIndex.set(null);
  }

  onDrop(event: DragEvent, dropIndex: number): void {
    event.preventDefault();
    const dragIndex = this.dragColumnIndex();
    if (dragIndex === null || dragIndex === dropIndex) return;

    const order = [...this.preferencesService.columnOrder()];
    const [moved] = order.splice(dragIndex, 1);
    order.splice(dropIndex, 0, moved);
    this.preferencesService.setColumnOrder(order);

    this.dragColumnIndex.set(null);
    this.dropTargetIndex.set(null);
  }

  onDragEnd(): void {
    this.dragColumnIndex.set(null);
    this.dropTargetIndex.set(null);
  }
}
